import hashlib, json

# Record tool description hashes at vetting time
APPROVED_TOOL_DESCRIPTION_HASHES: dict[str, str] = {
    "crm_search":        "sha256:4a8f2b...",
    "crm_get_contact":   "sha256:7c1d4e...",
    "weather_current":   "sha256:2b9f3a...",
}

def hash_tool_description(description: dict) -> str:
    canonical = json.dumps(description, sort_keys=True, ensure_ascii=True)
    return "sha256:" + hashlib.sha256(canonical.encode()).hexdigest()

def verify_tool_descriptions(server_tools: list[dict]) -> list[str]:
    """
    Returns a list of tool names whose descriptions have changed since vetting.
    An empty list means all descriptions match.
    """
    mismatches = []
    for tool in server_tools:
        name = tool.get("name", "")
        expected = APPROVED_TOOL_DESCRIPTION_HASHES.get(name)
        if expected is None:
            mismatches.append(f"UNKNOWN_TOOL:{name}")
            continue
        actual = hash_tool_description(tool)
        if actual != expected:
            mismatches.append(f"DESCRIPTION_CHANGED:{name}")
    return mismatches

