from pydantic import BaseModel, ValidationError
from typing import Any

# Declare the EXPECTED schema for each approved tool.
# These are authored by your security team — not taken from the server.
APPROVED_TOOL_SCHEMAS: dict[str, type[BaseModel]] = {}

def register_approved_schema(tool_name: str):
    """Decorator to register a Pydantic model as the canonical schema."""
    def decorator(cls):
        APPROVED_TOOL_SCHEMAS[tool_name] = cls
        return cls
    return decorator

@register_approved_schema("search_web")
class SearchWebArgs(BaseModel):
    query: str
    max_results: int = 5

@register_approved_schema("read_file")
class ReadFileArgs(BaseModel):
    path: str           # validated externally for path traversal

@register_approved_schema("send_email")
class SendEmailArgs(BaseModel):
    to: str
    subject: str
    body: str

def validated_tool_call(tool_name: str, raw_args: dict[str, Any]) -> BaseModel:
    schema = APPROVED_TOOL_SCHEMAS.get(tool_name)
    if schema is None:
        raise PermissionError(
            f"Tool '{tool_name}' has no approved schema — call blocked."
        )
    try:
        return schema(**raw_args)
    except ValidationError as exc:
        raise ValueError(
            f"Tool '{tool_name}' args failed schema validation: {exc}"
        ) from exc

# Usage inside the dispatcher
def dispatch_tool(tool_name: str, raw_args: dict) -> dict:
    validated = validated_tool_call(tool_name, raw_args)  # raises if invalid
    return _execute_tool(tool_name, validated.model_dump())
